// main.bicep — targetScope must be 'subscription' to create resource groups
targetScope = 'subscription'

param location string = 'eastus'
param environment string = 'prod'
param application string = 'myapp'

resource rg 'Microsoft.Resources/resourceGroups@2021-04-01' = {
  name: '${application}-${environment}-compute'
  location: location
  tags: {
    environment: environment
    application: application
    team: 'platform'
    costCenter: 'cc-1042'
  }
}

output resourceGroupName string = rg.name

from concurrent.futures import ThreadPoolExecutor, as_completed
from azure.identity import DefaultAzureCredential
from azure.mgmt.resource import ResourceManagementClient
from azure.mgmt.resource.resources.models import ResourceGroup
from azure.core.exceptions import HttpResponseError

credential = DefaultAzureCredential()
client = ResourceManagementClient(credential, '00000000-0000-0000-0000-000000000000')

ENVIRONMENTS = ['dev', 'staging', 'prod']
TIERS = ['networking', 'compute', 'data']
APP = 'myapp'
LOCATION = 'eastus'

def create_rg(env, tier):
    name = f'{APP}-{env}-{tier}'
    try:
        rg = client.resource_groups.create_or_update(
            name,
            ResourceGroup(location=LOCATION, tags={'environment': env, 'tier': tier})
        )
        return name, 'created', None
    except HttpResponseError as e:
        return name, 'failed', str(e)

tasks = [(env, tier) for env in ENVIRONMENTS for tier in TIERS]
with ThreadPoolExecutor(max_workers=9) as executor:
    futures = {executor.submit(create_rg, env, tier): (env, tier) for env, tier in tasks}
    for future in as_completed(futures):
        name, status, error = future.result()
        if error:
            print(f'  FAILED {name}: {error}')
        else:
            print(f'  OK     {name}')

// modules/resource-group.bicep — targetScope = 'subscription'
targetScope = 'subscription'

param name string
param location string
param environment string
param application string
param costCenter string
param contributorGroupId string  // Azure AD group object ID

resource rg 'Microsoft.Resources/resourceGroups@2021-04-01' = {
  name: name
  location: location
  tags: {
    environment: environment
    application: application
    'cost-center': costCenter
  }
}

// Protect production groups from accidental deletion
module lock './rg-lock.bicep' = if (environment == 'prod') {
  name: 'rg-lock'
  scope: rg
  params: { lockName: 'protect-prod' }
}

// Assign Contributor to the team group
module rbac './rg-rbac.bicep' = {
  name: 'rg-rbac'
  scope: rg
  params: {
    principalId: contributorGroupId
    roleDefinitionId: 'b24988ac-6180-42a0-ab88-20f7382dd24c'  // Contributor
  }
}

output resourceGroupId string = rg.id
